import type { Bot } from "grammy";
import type { TelegramSendQueue } from "./send-queue.js";
import { formatToolCall, formatToolUpdate } from "./formatting.js";
import { createChildLogger } from "../../core/log.js";
import type { ToolCallMeta, ViewerLinks } from "../shared/format-types.js";

const log = createChildLogger({ module: "tool-call-tracker" });

interface ToolCallState {
  msgId: number;
  name: string;
  kind?: string;
  rawInput?: unknown;
  viewerLinks?: ViewerLinks;
  viewerFilePath?: string;
  ready: Promise<void>;
}

export class ToolCallTracker {
  private sessions: Map<string, Map<string, ToolCallState>> = new Map();

  constructor(
    private bot: Bot,
    private chatId: number,
    private sendQueue: TelegramSendQueue,
  ) {}

  async trackNewCall(
    sessionId: string,
    threadId: number,
    meta: ToolCallMeta,
  ): Promise<void> {
    if (!this.sessions.has(sessionId)) {
      this.sessions.set(sessionId, new Map());
    }

    let resolveReady!: () => void;
    const ready = new Promise<void>((r) => {
      resolveReady = r;
    });

    this.sessions.get(sessionId)!.set(meta.id, {
      msgId: 0,
      name: meta.name,
      kind: meta.kind,
      rawInput: meta.rawInput,
      viewerLinks: meta.viewerLinks,
      viewerFilePath: meta.viewerFilePath,
      ready,
    });

import type { Bot } from 'grammy'
import { createChildLogger } from '../../core/log.js'
import { formatUsage } from './formatting.js'
import type { TelegramSendQueue } from './send-queue.js'
import type { PlanEntry } from '../../core/types.js'

const log = createChildLogger({ module: 'telegram:activity' })

// ─── ThinkingIndicator ────────────────────────────────────────────────────────

const THINKING_REFRESH_MS = 15_000
const THINKING_MAX_MS = 3 * 60 * 1000

export class ThinkingIndicator {
  private msgId?: number
  private sending = false
  private dismissed = false
  private refreshTimer?: ReturnType<typeof setInterval>
  private showTime = 0

  constructor(
    private api: Bot['api'],
    private chatId: number,
    private threadId: number,
    private sendQueue: TelegramSendQueue,
  ) {}

  async show(): Promise<void> {
    if (this.msgId || this.sending || this.dismissed) return
    this.sending = true
    this.showTime = Date.now()
    try {
      const result = await this.sendQueue.enqueue(() =>
        this.api.sendMessage(this.chatId, '💭 <i>Thinking...</i>', {
          message_thread_id: this.threadId,
          parse_mode: 'HTML',
          disable_notification: true,
        }),
      )
      if (result && !this.dismissed) {
        this.msgId = result.message_id
        this.startRefreshTimer()
      }
    } catch (err) {
      log.warn({ err }, 'ThinkingIndicator.show() failed')
    } finally {
      this.sending = false
    }
  }

