488→// src/adapters/shared/message-formatter.ts
489→import type { OutgoingMessage } from "../../core/index.js";
490→import type { FormattedMessage, MessageMetadata } from "./format-types.js";
491→import { STATUS_ICONS, KIND_ICONS, MESSAGE_ICONS } from "./format-types.js";
492→import { formatTokens } from "./format-utils.js";
493→
494→export function extractContentText(content: unknown, depth = 0): string {
495→  if (!content || depth > 5) return "";
496→  if (typeof content === "string") return content;
497→  if (Array.isArray(content)) {
498→    return content.map((c) => extractContentText(c, depth + 1)).filter(Boolean).join("\n");
499→  }
500→  if (typeof content !== "object") return String(content);
501→
502→  const obj = content as Record<string, unknown>;
503→
504→  if (obj.text && typeof obj.text === "string") return obj.text;
505→  if (obj.content) {
506→    if (typeof obj.content === "string") return obj.content;
507→    if (Array.isArray(obj.content)) {
508→      return obj.content.map((c) => extractContentText(c, depth + 1)).filter(Boolean).join("\n");
509→    }
510→    return extractContentText(obj.content, depth + 1);
511→  }
512→  if (obj.input && typeof obj.input === "string") return obj.input;
513→  if (obj.output && typeof obj.output === "string") return obj.output;
514→  return "";
515→}
516→
517→export function formatToolSummary(name: string, rawInput: unknown): string {
518→  let args: Record<string, unknown> = {};
519→  try {
520→    if (typeof rawInput === "string") {
521→      args = JSON.parse(rawInput);
522→    } else if (typeof rawInput === "object" && rawInput !== null) {
523→      args = rawInput as Record<string, unknown>;
524→    }
525→  } catch {
526→    return `🔧 ${name}`;
527→  }
528→
529→  const lowerName = name.toLowerCase();
530→
531→  if (lowerName === "read") {
532→    const fp = args.file_path ?? args.filePath ?? "";
533→    const limit = args.limit ? ` (${args.limit} lines)` : "";
534→    return fp ? `📖 Read ${fp}${limit}` : `🔧 ${name}`;
535→  }
536→  if (lowerName === "edit") {
537→    const fp = args.file_path ?? args.filePath ?? "";
538→    return fp ? `✏️ Edit ${fp}` : `🔧 ${name}`;
539→  }
540→  if (lowerName === "write") {
541→    const fp = args.file_path ?? args.filePath ?? "";
542→    return fp ? `✏️ Write ${fp}` : `🔧 ${name}`;
543→  }
544→  if (lowerName === "bash") {
545→    const cmd = String(args.command ?? "").slice(0, 60);
546→    return cmd ? `▶️ Run: ${cmd}` : `🔧 ${name}`;
547→  }
548→  if (lowerName === "grep") {
549→    const pattern = args.pattern ?? "";
550→    const path = args.path ?? "";
551→    return pattern ? `🔍 Grep "${pattern}"${path ? ` in ${path}` : ""}` : `🔧 ${name}`;
552→  }
553→  if (lowerName === "glob") {
554→    const pattern = args.pattern ?? "";
555→    return pattern ? `🔍 Glob ${pattern}` : `🔧 ${name}`;
556→  }
557→  if (lowerName === "agent") {
558→    const desc = String(args.description ?? "").slice(0, 60);
559→    return desc ? `🧠 Agent: ${desc}` : `🔧 ${name}`;
560→  }
561→  if (lowerName === "webfetch" || lowerName === "web_fetch") {
562→    const url = String(args.url ?? "").slice(0, 60);
563→    return url ? `🌐 Fetch ${url}` : `🔧 ${name}`;
564→  }
565→  if (lowerName === "websearch" || lowerName === "web_search") {
566→    const query = String(args.query ?? "").slice(0, 60);
567→    return query ? `🌐 Search "${query}"` : `🔧 ${name}`;
568→  }
569→
570→  return `🔧 ${name}`;
571→}
572→
573→export function formatOutgoingMessage(msg: OutgoingMessage): FormattedMessage {
574→  const meta = (msg.metadata ?? {}) as Record<string, unknown>;
575→
576→  switch (msg.type) {
577→    case "text":
578→      return { summary: msg.text, icon: "", originalType: "text", style: "text" };
579→
580→    case "thought": {
581→      const full = msg.text;
582→      const summary = full.length > 80 ? full.slice(0, 80) + "..." : full;
583→      return { summary, detail: full.length > 80 ? full : undefined, icon: "💭", originalType: "thought", style: "thought" };
584→    }
585→
586→    case "tool_call": {
587→      const name = String(meta.name ?? msg.text ?? "Tool");
588→      const kind = String(meta.kind ?? "other");
589→      const status = String(meta.status ?? "pending");
590→      const rawInput = meta.rawInput;
591→      const summary = formatToolSummary(name, rawInput);
592→      const statusIcon = STATUS_ICONS[status] ?? "⏳";
593→      const detail = extractContentText(meta.content);
594→      return {
595→        summary: `${statusIcon} ${summary}`,
596→        detail: detail || undefined,
597→        icon: KIND_ICONS[kind] ?? "🔧",
598→        originalType: "tool_call",
599→        style: "tool",
600→        metadata: { toolName: name, toolStatus: status, toolKind: kind },
601→      };
602→    }
603→
604→    case "tool_update": {
605→      const name = String(meta.name ?? msg.text ?? "Tool");
606→      const kind = String(meta.kind ?? "other");
607→      const status = String(meta.status ?? "completed");
608→      const rawInput = meta.rawInput;
609→      const summary = formatToolSummary(name, rawInput);
610→      const statusIcon = STATUS_ICONS[status] ?? "✅";
611→      const detail = extractContentText(meta.content);
612→      return {
613→        summary: `${statusIcon} ${summary}`,
614→        detail: detail || undefined,
615→        icon: KIND_ICONS[kind] ?? "🔧",
616→        originalType: "tool_update",
617→        style: "tool",
618→        metadata: { toolName: name, toolStatus: status, toolKind: kind },
619→      };
620→    }
621→
622→    case "plan": {
623→      const entries = (meta.entries ?? []) as { content: string; status: string }[];
624→      const summary = `📋 Plan: ${entries.length} steps`;
625→      return {
626→        summary,
627→        icon: "📋",
628→        originalType: "plan",
629→        style: "plan",
630→        metadata: { planEntries: entries },
631→      };
632→    }
633→
634→    case "usage": {
635→      const tokens = Number(meta.tokensUsed ?? 0);
636→      // cost may be { amount, currency } object or number
637→      const costObj = meta.cost as { amount?: number; currency?: string } | number | undefined;
638→      const costAmount = typeof costObj === "number" ? costObj : (costObj?.amount ?? 0);
639→      const summary = `📊 ${formatTokens(tokens)} tokens${costAmount ? ` · $${costAmount.toFixed(2)}` : ""}`;
640→      return {
641→        summary,
642→        icon: "📊",
643→        originalType: "usage",
644→        style: "usage",
645→        metadata: { tokens, contextSize: Number(meta.contextSize ?? 0), cost: costAmount },
646→      };
647→    }
648→
649→    case "error":
650→      return {
651→        summary: msg.text.length > 120 ? msg.text.slice(0, 120) + "..." : msg.text,
652→        detail: msg.text.length > 120 ? msg.text : undefined,
653→        icon: "❌",
654→        originalType: "error",
655→        style: "error",
656→      };
657→
658→    case "session_end":
659→      return {
660→        summary: `Session ${msg.text}`,
661→        icon: msg.text === "completed" ? "✅" : "❌",
662→        originalType: "session_end",
663→        style: "system",
664→      };
665→
666→    case "system_message":
667→      return { summary: msg.text, icon: "ℹ️", originalType: "system_message", style: "system" };
