  1→import type { OutgoingMessage } from "../../core/types.js";
  2→import type {
  3→  FormattedMessage,
  4→  MessageMetadata,
  5→  DisplayVerbosity,
  6→  NoiseAction,
  7→  NoiseRule,
  8→} from "./format-types.js";
  9→import { STATUS_ICONS, KIND_ICONS } from "./format-types.js";
 10→import { formatTokens } from "./format-utils.js";
 11→
 12→export function extractContentText(content: unknown, depth = 0): string {
 13→  if (!content || depth > 5) return "";
 14→  if (typeof content === "string") return content;
 15→  if (Array.isArray(content)) {
 16→    return content
 17→      .map((c) => extractContentText(c, depth + 1))
 18→      .filter(Boolean)
 19→      .join("\n");
 20→  }
 21→  if (typeof content !== "object") return String(content);
 22→
 23→  const obj = content as Record<string, unknown>;
 24→  if (obj.text && typeof obj.text === "string") return obj.text;
 25→  if (obj.content) {
 26→    if (typeof obj.content === "string") return obj.content;
 27→    if (Array.isArray(obj.content)) {
 28→      return obj.content
 29→        .map((c) => extractContentText(c, depth + 1))
 30→        .filter(Boolean)
 31→        .join("\n");
 32→    }
 33→    return extractContentText(obj.content, depth + 1);
 34→  }
 35→  if (obj.input && typeof obj.input === "string") return obj.input;
 36→  if (obj.output && typeof obj.output === "string") return obj.output;
 37→  return "";
 38→}
 39→
 40→function parseRawInput(rawInput: unknown): Record<string, unknown> {
 41→  try {
 42→    if (typeof rawInput === "string") {
 43→      return JSON.parse(rawInput) as Record<string, unknown>;
 44→    }
 45→    if (typeof rawInput === "object" && rawInput !== null) {
 46→      return rawInput as Record<string, unknown>;
 47→    }
 48→  } catch {
 49→    // fall through
 50→  }
 51→  return {};
 52→}
 53→
 54→// --- Step 5: formatToolSummary with displaySummary override ---
 55→
 56→export function formatToolSummary(
 57→  name: string,
 58→  rawInput: unknown,
 59→  displaySummary?: string,
 60→): string {
 61→  if (displaySummary && typeof displaySummary === "string") {
 62→    return displaySummary;
 63→  }
 64→
 65→  const args = parseRawInput(rawInput);
 66→  const lowerName = name.toLowerCase();
 67→
 68→  if (lowerName === "read") {
 69→    const fp = args.file_path ?? args.filePath ?? "";
 70→    const limit = args.limit ? ` (${args.limit} lines)` : "";
 71→    return fp ? `📖 Read ${fp}${limit}` : `🔧 ${name}`;
 72→  }
 73→  if (lowerName === "edit") {
 74→    const fp = args.file_path ?? args.filePath ?? "";
 75→    return fp ? `✏️ Edit ${fp}` : `🔧 ${name}`;
 76→  }
 77→  if (lowerName === "write") {
 78→    const fp = args.file_path ?? args.filePath ?? "";
 79→    return fp ? `📝 Write ${fp}` : `🔧 ${name}`;
 80→  }
 81→  if (lowerName === "bash") {
 82→    const cmd = String(args.command ?? "").slice(0, 60);
 83→    return cmd ? `▶️ Run: ${cmd}` : `🔧 ${name}`;
 84→  }
 85→  if (lowerName === "grep") {
 86→    const pattern = args.pattern ?? "";
 87→    const path = args.path ?? "";
 88→    return pattern
 89→      ? `🔍 Grep "${pattern}"${path ? ` in ${path}` : ""}`
 90→      : `🔧 ${name}`;
 91→  }
 92→  if (lowerName === "glob") {
 93→    const pattern = args.pattern ?? "";
 94→    return pattern ? `🔍 Glob ${pattern}` : `🔧 ${name}`;
 95→  }
 96→  if (lowerName === "agent") {
 97→    const desc = String(args.description ?? "").slice(0, 60);
 98→    return desc ? `🧠 Agent: ${desc}` : `🔧 ${name}`;
 99→  }
100→  if (lowerName === "webfetch" || lowerName === "web_fetch") {
101→    const url = String(args.url ?? "").slice(0, 60);
102→    return url ? `🌐 Fetch ${url}` : `🔧 ${name}`;
103→  }
104→  if (lowerName === "websearch" || lowerName === "web_search") {
105→    const query = String(args.query ?? "").slice(0, 60);
106→    return query ? `🌐 Search "${query}"` : `🔧 ${name}`;
107→  }
108→
109→  return `🔧 ${name}`;
110→}
111→
112→// --- Step 6: formatToolTitle for low verbosity ---
113→
114→export function formatToolTitle(
115→  name: string,
116→  rawInput: unknown,
117→  displayTitle?: string,
118→): string {
119→  if (displayTitle && typeof displayTitle === "string") {
120→    return displayTitle;
121→  }
122→
123→  const args = parseRawInput(rawInput);
124→  const lowerName = name.toLowerCase();
125→
126→  if (["read", "edit", "write"].includes(lowerName)) {
127→    return String(args.file_path ?? args.filePath ?? name);
128→  }
129→  if (lowerName === "bash") {
130→    return String(args.command ?? name).slice(0, 60);
131→  }
132→  if (lowerName === "grep") {
133→    const pattern = args.pattern ?? "";
134→    const path = args.path ?? "";
135→    return pattern ? `"${pattern}"${path ? ` in ${path}` : ""}` : name;
136→  }
137→  if (lowerName === "glob") {
138→    return String(args.pattern ?? name);
139→  }
140→  if (lowerName === "agent") {
141→    return String(args.description ?? name).slice(0, 60);
142→  }
143→  if (["webfetch", "web_fetch"].includes(lowerName)) {
144→    return String(args.url ?? name).slice(0, 60);
145→  }
146→  if (["websearch", "web_search"].includes(lowerName)) {
147→    return String(args.query ?? name).slice(0, 60);
148→  }
149→
150→  return name;
151→}
152→
153→// --- Step 7: Noise filtering ---
154→
155→const NOISE_RULES: NoiseRule[] = [
156→  {
157→    match: (name) => name.toLowerCase() === "ls",
158→    action: "hide",
159→  },
160→  {
161→    match: (_name, kind, rawInput) => {
162→      if (kind !== "read") return false;
163→      const args = parseRawInput(rawInput);
164→      const p = String(args.file_path ?? args.filePath ?? args.path ?? "");
165→      return p.endsWith("/");
166→    },
167→    action: "hide",
168→  },
169→  {
170→    match: (name) => name.toLowerCase() === "glob",
171→    action: "collapse",
172→  },
173→];
174→
175→export function evaluateNoise(
176→  name: string,
177→  kind: string,
178→  rawInput: unknown,
179→): NoiseAction | null {
180→  for (const rule of NOISE_RULES) {
181→    if (rule.match(name, kind, rawInput)) return rule.action;
182→  }
183→  return null;
184→}
185→
186→// --- Step 8: formatOutgoingMessage with verbosity + noise + viewerLinks ---
187→
188→function buildViewerLinks(
189→  meta: Record<string, unknown>,
190→): { type: "file" | "diff"; url: string; label: string }[] | undefined {
191→  const vl = meta.viewerLinks as Record<string, string> | undefined;
192→  if (!vl) return undefined;
193→
194→  const filePath = String(meta.viewerFilePath ?? "file");
195→  const links: { type: "file" | "diff"; url: string; label: string }[] = [];
196→  if (vl.file)
197→    links.push({ type: "file", url: vl.file, label: `📄 View ${filePath}` });
198→  if (vl.diff)
199→    links.push({
200→      type: "diff",
201→      url: vl.diff,
202→      label: `📝 View diff — ${filePath}`,
203→    });
204→  return links.length > 0 ? links : undefined;
205→}
206→
207→function formatToolMessage(
208→  meta: Record<string, unknown>,
209→  msgType: string,
210→  msgText: string,
211→  verbosity: DisplayVerbosity,
212→): FormattedMessage | null {
213→  const name = String(meta.name ?? msgText ?? "Tool");
214→  const kind = String(meta.displayKind ?? meta.kind ?? "other");
215→  const status = String(
216→    meta.status ?? (msgType === "tool_update" ? "completed" : "pending"),
217→  );
218→  const rawInput = meta.rawInput;
219→  const displaySummary = meta.displaySummary as string | undefined;
220→  const displayTitle = meta.displayTitle as string | undefined;
221→  const statusIcon = STATUS_ICONS[status] ?? "⏳";
222→  const kindIcon = KIND_ICONS[kind] ?? "🔧";
223→  const viewerLinks = buildViewerLinks(meta);
224→
225→  const noiseAction = evaluateNoise(name, kind, rawInput);
226→
227→  if (noiseAction === "hide" && verbosity !== "high") return null;
228→  if (noiseAction === "hide" && verbosity === "high") {
229→    return {
230→      summary: `${statusIcon} ${formatToolTitle(name, rawInput, displayTitle)}`,
231→      viewerLinks,
232→      icon: kindIcon,
233→      originalType: msgType,
234→      style: "tool",
235→      metadata: { toolName: name, toolStatus: status, toolKind: kind },
236→    };
237→  }
238→  if (noiseAction === "collapse" && verbosity === "low") return null;
239→  if (noiseAction === "collapse" && verbosity === "medium") {
240→    return {
241→      summary: `${statusIcon} ${kindIcon}`,
242→      viewerLinks,
243→      icon: kindIcon,
244→      originalType: msgType,
245→      style: "tool",
246→      metadata: { toolName: name, toolStatus: status, toolKind: kind },
247→    };
248→  }
249→
250→  const summary =
251→    verbosity === "low"
252→      ? `${statusIcon} ${formatToolTitle(name, rawInput, displayTitle)}`
253→      : `${statusIcon} ${formatToolSummary(name, rawInput, displaySummary)}`;
254→
255→  const detail =
256→    verbosity === "high"
257→      ? extractContentText(meta.content) || undefined
258→      : undefined;
259→
260→  return {
261→    summary,
262→    detail,
263→    viewerLinks,
264→    icon: kindIcon,
265→    originalType: msgType,
266→    style: "tool",
267→    metadata: { toolName: name, toolStatus: status, toolKind: kind },
268→  };
269→}
270→
271→export function formatOutgoingMessage(
272→  msg: OutgoingMessage,
273→  verbosity: DisplayVerbosity = "medium",
274→): FormattedMessage | null {
275→  const meta = (msg.metadata ?? {}) as Record<string, unknown>;
276→
277→  switch (msg.type) {
278→    case "text":
279→      return {
280→        summary: msg.text,
281→        icon: "",
282→        originalType: "text",
283→        style: "text",
284→      };
285→
286→    case "thought": {
287→      const full = msg.text;
288→      const summary = full.length > 80 ? full.slice(0, 80) + "..." : full;
289→      return {
290→        summary,
291→        detail: full.length > 80 ? full : undefined,
292→        icon: "💭",
293→        originalType: "thought",
294→        style: "thought",
295→      };
296→    }
297→
298→    case "tool_call":
299→      return formatToolMessage(meta, "tool_call", msg.text, verbosity);
300→
301→    case "tool_update":
302→      return formatToolMessage(meta, "tool_update", msg.text, verbosity);
303→
304→    case "plan": {
305→      const entries = (meta.entries ?? []) as {
306→        content: string;
307→        status: string;
308→      }[];
309→      return {
310→        summary: `📋 Plan: ${entries.length} steps`,
311→        icon: "📋",
312→        originalType: "plan",
313→        style: "plan",
314→        metadata: { planEntries: entries } satisfies MessageMetadata,
315→      };
316→    }
317→
318→    case "usage": {
319→      const tokens = Number(meta.tokensUsed ?? 0);
320→      const costObj = meta.cost as
321→        | { amount?: number; currency?: string }
322→        | number
323→        | undefined;
324→      const costAmount =
325→        typeof costObj === "number" ? costObj : (costObj?.amount ?? 0);
326→      const summary = `📊 ${formatTokens(tokens)} tokens${costAmount ? ` · $${costAmount.toFixed(2)}` : ""}`;
327→      return {
328→        summary,
329→        icon: "📊",
330→        originalType: "usage",
331→        style: "usage",
332→        metadata: {
333→          tokens,
334→          contextSize: Number(meta.contextSize ?? 0),
335→          cost: costAmount,
336→        },
337→      };
338→    }
339→
340→    case "error": {
341→      const full = msg.text;
342→      return {
343→        summary: full.length > 120 ? full.slice(0, 120) + "..." : full,
344→        detail: full.length > 120 ? full : undefined,
345→        icon: "❌",
346→        originalType: "error",
347→        style: "error",
348→      };
349→    }
350→
351→    case "session_end":
352→      return {
353→        summary: `Session ${msg.text}`,
354→        icon: msg.text.includes("completed") ? "✅" : "❌",
355→        originalType: "session_end",
356→        style: "system",
357→      };
358→
359→    case "system_message":
360→      return {
361→        summary: msg.text,
362→        icon: "ℹ️",
363→        originalType: "system_message",
364→        style: "system",
365→      };
366→
367→    case "attachment":
368→      return {
369→        summary: msg.text || "File",
370→        icon: "📎",
371→        originalType: "attachment",
372→        style: "attachment",
373→      };
374→
375→    default:
376→      return {
377→        summary: msg.text || "",
378→        icon: "",
379→        originalType: msg.type,
380→        style: "text",
381→      };
382→  }
383→}
384→

