236→  // ─── Message handler ──────────────────────────────────────────────────────
237→
238→  private setupMessageHandler(): void {
239→    this.client.on("messageCreate", async (message) => {
240→      try {
241→        // Ignore bots and self
242→        if (message.author.bot) return;
243→
244→        // Ignore DMs
245→        if (!message.guild) return;
246→
247→        // Ignore messages from the wrong guild
248→        if (message.guild.id !== this.guild.id) return;
249→
250→        // Only process messages in threads
251→        if (!message.channel.isThread()) return;
252→
253→        const threadId = message.channel.id;
254→        const userId = message.author.id;
255→        let text = message.content;
256→
257→        log.debug(
258→          {
259→            threadId,
260→            userId,
261→            text: text.slice(0, 50),
262→            attachmentCount: message.attachments.size,
263→          },
264→          "[DiscordAdapter] messageCreate received",
265→        );
266→
267→        // Ignore messages with no text and no attachments
268→        if (!text && message.attachments.size === 0) return;
269→
270→        // Resolve sessionId for file storage (fallback to "unknown" for new sessions)
271→        const sessionId =
272→          this.core.sessionManager.getSessionByThread("discord", threadId)
273→            ?.id ?? "unknown";
274→
275→        // Process attachments
276→        if (message.attachments.size > 0) {
277→          log.info(
278→            {
279→              sessionId,
280→              attachments: message.attachments.map((a) => ({
281→                name: a.name,
282→                size: a.size,
283→                contentType: a.contentType,
284→                url: a.url?.slice(0, 80),
285→              })),
286→            },
287→            "[discord-media] Processing incoming attachments",
288→          );
289→        }
290→        const attachments = await this.processIncomingAttachments(
291→          message,
292→          sessionId,
293→        );
294→
295→        // Generate fallback text if message has attachments but no text
296→        if (!text && attachments.length > 0) {
297→          text = buildFallbackText(attachments);
298→        }
299→
300→        // If all attachment downloads failed and no text, notify user
301→        if (!text && attachments.length === 0 && message.attachments.size > 0) {
302→          try {
303→            await message.reply("Failed to process attachment(s)");
304→          } catch {
305→            /* best effort */
306→          }
307→          return;
308→        }
309→
310→        // Route assistant thread messages to assistant
311→        if (
312→          this.discordConfig.assistantThreadId &&
313→          threadId === this.discordConfig.assistantThreadId
314→        ) {
315→          if (this.assistantSession && text) {
316→            await this.assistantSession.enqueuePrompt(
