322→        }
323→
324→        // Route to core for session dispatch
325→        await this.core.handleMessage({
326→          channelId: "discord",
327→          threadId,
328→          userId,
329→          text,
330→          ...(attachments.length > 0 ? { attachments } : {}),
331→        });
332→      } catch (err) {
333→        log.error({ err }, "[DiscordAdapter] messageCreate handler error");
334→      }
335→    });
336→  }
