338→  // ─── Assistant ────────────────────────────────────────────────────────────
339→
340→  private async setupAssistant(): Promise<void> {
341→    let threadId = this.discordConfig.assistantThreadId;
342→
343→    // Verify existing thread is still accessible
344→    if (threadId) {
345→      try {
346→        const existing =
347→          this.guild.channels.cache.get(threadId) ??
