408→  // ─── Incoming media ──────────────────────────────────────────────────
409→
410→  private async processIncomingAttachments(
411→    message: import("discord.js").Message,
412→    sessionId: string,
413→  ): Promise<Attachment[]> {
414→    if (message.attachments.size === 0) return [];
415→
416→    const isVoiceMessage = message.flags.has(MessageFlags.IsVoiceMessage);
417→
418→    const results = await Promise.allSettled(
419→      message.attachments.map(async (discordAtt) => {
420→        const buffer = await downloadDiscordAttachment(
421→          discordAtt.url,
422→          discordAtt.name ?? "attachment",
423→        );
424→        if (!buffer) return null;
425→
426→        let data = buffer;
427→        let fileName = discordAtt.name ?? "attachment";
428→        let mimeType = discordAtt.contentType ?? "application/octet-stream";
429→
430→        // Convert voice messages from OGG Opus to WAV
431→        if (isVoiceMessage && mimeType.includes("ogg")) {
432→          try {
433→            data = await this.fileService.convertOggToWav(buffer);
434→            fileName = "voice.wav";
435→            mimeType = "audio/wav";
436→          } catch (err) {
437→            log.warn(
438→              { err },
439→              "[discord-media] OGG→WAV conversion failed, saving original",
440→            );
441→          }
442→        }
443→
444→        return this.fileService.saveFile(sessionId, fileName, data, mimeType);
445→      }),
446→    );
447→
448→    const rejected = results.filter((r) => r.status === "rejected");
449→    if (rejected.length > 0) {
450→      log.warn(
451→        { rejected: rejected.map((r) => (r as PromiseRejectedResult).reason) },
452→        "[discord-media] Some attachments failed",
453→      );
454→    }
455→
456→    const saved = results
457→      .filter(
458→        (r): r is PromiseFulfilledResult<Attachment | null> =>
459→          r.status === "fulfilled",
460→      )
461→      .map((r) => r.value)
462→      .filter((att): att is Attachment => att !== null);
463→
464→    log.info(
465→      { count: saved.length, files: saved.map((a) => a.fileName) },
466→      "[discord-media] Attachments processed",
467→    );
468→    return saved;
469→  }
