471→  // ─── Helper: resolve thread ───────────────────────────────────────────────
472→
473→  private async getThread(sessionId: string): Promise<ThreadChannel | null> {
474→    const session = this.core.sessionManager.getSession(sessionId);
475→    const threadId = session?.threadId;
