514→  // --- MessageHandlers for dispatchMessage ---
515→
516→  private messageHandlers: MessageHandlers<DiscordMessageCtx> = {
517→    onThought: async (ctx, _content) => {
518→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
519→      await tracker.onThought();
520→    },
521→
522→    onText: async (ctx, content) => {
523→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
