529→
530→    onToolCall: async (ctx, content) => {
531→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
532→      await tracker.onToolCall();
533→      await this.draftManager.finalize(
534→        ctx.sessionId,
535→        ctx.thread,
536→        ctx.isAssistant,
537→      );
538→      const meta = content.metadata ?? {};
539→      await this.toolTracker.trackNewCall(
540→        ctx.sessionId,
541→        ctx.thread,
542→        {
543→          id: String(meta.id ?? ""),
544→          name: content.text || String(meta.name ?? "Tool"),
545→          kind: meta.kind as string | undefined,
546→          status: String(meta.status ?? "running"),
547→          content: meta.content,
548→          rawInput: meta.rawInput,
