553→      );
554→    },
555→
556→    onToolUpdate: async (ctx, content) => {
557→      const meta = content.metadata ?? {};
558→      await this.toolTracker.updateCall(
559→        ctx.sessionId,
560→        {
561→          id: String(meta.id ?? ""),
562→          name: content.text || String(meta.name ?? ""),
563→          kind: meta.kind as string | undefined,
564→          status: String(meta.status ?? "completed"),
