569→        },
570→        this.verbosity,
571→      );
572→    },
573→
574→    onPlan: async (ctx, content) => {
575→      const entries = (content.metadata?.entries ?? []) as PlanEntry[];
576→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
577→      await tracker.onPlan(entries);
