655→
656→      // Discord free tier limit: 25MB
657→      if (isAttachmentTooLarge(attachment.size)) {
658→        log.warn(
659→          {
660→            sessionId: ctx.sessionId,
661→            fileName: attachment.fileName,
662→            size: attachment.size,
663→          },
664→          "[discord-media] File too large (>25MB)",
665→        );
666→        try {
667→          await this.sendQueue.enqueue(
668→            () =>
669→              ctx.thread.send({
670→                content: `⚠️ File too large to send (${Math.round(attachment.size / 1024 / 1024)}MB): ${attachment.fileName}`,
671→              }),
672→            { type: "other" },
673→          );
674→        } catch {
675→          /* best effort */
676→        }
677→        return;
678→      }
679→
680→      try {
681→        await this.sendQueue.enqueue(
682→          () =>
683→            ctx.thread.send({
684→              files: [
685→                { attachment: attachment.filePath, name: attachment.fileName },
686→              ],
687→            }),
688→          { type: "other" },
689→        );
690→
691→        // Strip [TTS]...[/TTS] block from the text message after audio is sent.
692→        if (attachment.type === "audio") {
693→          const draft = this.draftManager.getDraft(ctx.sessionId);
694→          if (draft) {
695→            draft.stripPattern(/\[TTS\][\s\S]*?\[\/TTS\]/g).catch(() => {});
696→          }
697→        }
698→      } catch (err) {
699→        log.error(
700→          { err, sessionId: ctx.sessionId, fileName: attachment.fileName },
701→          "[discord-media] Failed to send attachment",
702→        );
703→      }
704→    },
705→
706→    onSystemMessage: async (ctx, content) => {
707→      try {
708→        await this.sendQueue.enqueue(
709→          () => ctx.thread.send({ content: content.text }),
710→          { type: "other" },
711→        );
712→      } catch {
713→        /* best effort */
714→      }
715→    },
716→  };
