718→  // ─── sendMessage ──────────────────────────────────────────────────────────
719→
720→  async sendMessage(
721→    sessionId: string,
722→    content: OutgoingMessage,
723→  ): Promise<void> {
724→    // Suppress output while assistant is initializing its system prompt
725→    if (
726→      this.assistantInitializing &&
727→      this.assistantSession &&
728→      sessionId === this.assistantSession.id
729→    ) {
730→      return;
731→    }
732→
733→    const thread = await this.getThread(sessionId);
734→    if (!thread) return;
735→
736→    await ensureUnarchived(thread);
737→
738→    const isAssistant =
739→      this.assistantSession != null && sessionId === this.assistantSession.id;
740→
741→    const ctx: DiscordMessageCtx = { sessionId, thread, isAssistant };
742→    await dispatchMessage(this.messageHandlers, ctx, content, this.verbosity);
743→  }
