746→
747→  async sendPermissionRequest(
748→    sessionId: string,
749→    request: PermissionRequest,
750→  ): Promise<void> {
751→    const session = this.core.sessionManager.getSession(sessionId);
752→    if (!session) {
753→      log.warn(
754→        { sessionId },
755→        "[DiscordAdapter] sendPermissionRequest: session not found",
756→      );
757→      return;
758→    }
759→
760→    const thread = await this.getThread(sessionId);
761→    if (!thread) return;
762→
763→    await this.permissionHandler.sendPermissionRequest(
764→      session,
765→      request,
766→      thread,
767→    );
768→  }
