770→  // ─── sendNotification ─────────────────────────────────────────────────────
771→
772→  async sendNotification(notification: NotificationMessage): Promise<void> {
773→    if (!this.notificationChannel) return;
774→
775→    const typeIcon: Record<string, string> = {
776→      completed: "✅",
777→      error: "❌",
778→      permission: "🔐",
779→      input_required: "💬",
780→    };
781→
782→    const icon = typeIcon[notification.type] ?? "ℹ️";
783→    const name = notification.sessionName
784→      ? ` **${notification.sessionName}**`
785→      : "";
786→    let text = `${icon}${name}: ${notification.summary}`;
787→    if (notification.deepLink) {
788→      text += `\n${notification.deepLink}`;
789→    }
790→
791→    try {
792→      await this.sendQueue.enqueue(
793→        () => this.notificationChannel.send({ content: text }),
794→        { type: "other" },
795→      );
796→    } catch (err) {
797→      log.warn({ err }, "[DiscordAdapter] Failed to send notification");
798→    }
799→  }
