801→  // ─── createSessionThread ─────────────────────────────────────────────────
802→
803→  async createSessionThread(sessionId: string, name: string): Promise<string> {
804→    const thread = await forumsCreateThread(this.forumChannel, name);
805→
806→    // Persist threadId on session record
807→    const session = this.core.sessionManager.getSession(sessionId);
808→    if (session) {
809→      session.threadId = thread.id;
810→    }
811→
812→    const record = this.core.sessionManager.getSessionRecord(sessionId);
813→    if (record) {
814→      await this.core.sessionManager.patchRecord(sessionId, {
815→        platform: { ...record.platform, threadId: thread.id },
816→      });
817→    }
818→
819→    return thread.id;
820→  }
