824→  async renameSessionThread(sessionId: string, newName: string): Promise<void> {
825→    const session = this.core.sessionManager.getSession(sessionId);
826→    const threadId = session?.threadId;
827→    if (!threadId) return;
828→    await forumsRenameThread(this.guild, threadId, newName);
829→  }
