832→
833→  override async deleteSessionThread(sessionId: string): Promise<void> {
834→    const session = this.core.sessionManager.getSession(sessionId);
835→    const threadId = session?.threadId;
836→    if (!threadId) return;
837→    await forumsDeleteThread(this.guild, threadId);
