 1→import type { OutgoingMessage } from "../../core/types.js";
 2→import type { DisplayVerbosity } from "./format-types.js";
 3→
 4→export interface MessageHandlers<TCtx = unknown> {
 5→  onText(ctx: TCtx, content: OutgoingMessage): Promise<void>;
 6→  onThought(ctx: TCtx, content: OutgoingMessage): Promise<void>;
 7→  onToolCall(ctx: TCtx, content: OutgoingMessage): Promise<void>;
 8→  onToolUpdate(ctx: TCtx, content: OutgoingMessage): Promise<void>;
 9→  onPlan(ctx: TCtx, content: OutgoingMessage): Promise<void>;
10→  onUsage(ctx: TCtx, content: OutgoingMessage): Promise<void>;
11→  onSessionEnd(ctx: TCtx, content: OutgoingMessage): Promise<void>;
12→  onError(ctx: TCtx, content: OutgoingMessage): Promise<void>;
13→  onAttachment(ctx: TCtx, content: OutgoingMessage): Promise<void>;
14→  onSystemMessage(ctx: TCtx, content: OutgoingMessage): Promise<void>;
15→}
16→
17→const HIDDEN_ON_LOW: Set<string> = new Set(["thought", "plan", "usage"]);
18→
19→export function shouldDispatch(
20→  type: string,
21→  verbosity: DisplayVerbosity,
22→): boolean {
23→  if (verbosity === "low" && HIDDEN_ON_LOW.has(type)) return false;
24→  return true;
25→}
26→
27→export async function dispatchMessage<TCtx>(
28→  handlers: MessageHandlers<TCtx>,
29→  ctx: TCtx,
30→  content: OutgoingMessage,
31→  verbosity: DisplayVerbosity = "medium",
32→): Promise<void> {
33→  if (!shouldDispatch(content.type, verbosity)) return;
34→
35→  switch (content.type) {
36→    case "text":
37→      return handlers.onText(ctx, content);
38→    case "thought":
39→      return handlers.onThought(ctx, content);
40→    case "tool_call":
41→      return handlers.onToolCall(ctx, content);
42→    case "tool_update":
43→      return handlers.onToolUpdate(ctx, content);
44→    case "plan":
45→      return handlers.onPlan(ctx, content);
46→    case "usage":
47→      return handlers.onUsage(ctx, content);
48→    case "session_end":
49→      return handlers.onSessionEnd(ctx, content);
50→    case "error":
51→      return handlers.onError(ctx, content);
52→    case "attachment":
53→      return handlers.onAttachment(ctx, content);
54→    case "system_message":
55→      return handlers.onSystemMessage(ctx, content);
56→    default:
57→      return;
58→  }
59→}
