  1→import type { TextChannel, ThreadChannel, Message } from 'discord.js'
  2→import { EmbedBuilder } from 'discord.js'
  3→import { log } from '../../core/log.js'
  4→import type { PlanEntry } from '../../core/types.js'
  5→import { formatUsage, formatPlan } from './formatting.js'
  6→import type { DiscordSendQueue } from './send-queue.js'
