  8→// ─── ThinkingIndicator ────────────────────────────────────────────────────────
  9→
 10→const TYPING_REFRESH_MS = 8_000
 11→
 12→export class ThinkingIndicator {
 13→  private dismissed = false
 14→  private refreshTimer?: ReturnType<typeof setInterval>
 15→
 16→  constructor(
 17→    private channel: TextChannel | ThreadChannel,
 18→  ) {}
 19→
 20→  async show(): Promise<void> {
 21→    if (this.dismissed) return
 22→    try {
 23→      await this.channel.sendTyping()
 24→      this.startRefreshTimer()
 25→    } catch (err) {
 26→      log.warn({ err }, '[ThinkingIndicator] sendTyping() failed')
 27→    }
 28→  }
 29→
 30→  dismiss(): void {
 31→    this.dismissed = true
 32→    this.stopRefreshTimer()
 33→  }
 34→
 35→  reset(): void {
 36→    this.dismissed = false
 37→  }
 38→
 39→  private startRefreshTimer(): void {
 40→    this.stopRefreshTimer()
 41→    this.refreshTimer = setInterval(() => {
 42→      if (this.dismissed) {
 43→        this.stopRefreshTimer()
 44→        return
 45→      }
 46→      this.channel.sendTyping().catch(() => {})
 47→    }, TYPING_REFRESH_MS)
 48→  }
 49→
 50→  private stopRefreshTimer(): void {
 51→    if (this.refreshTimer) {
 52→      clearInterval(this.refreshTimer)
 53→      this.refreshTimer = undefined
 54→    }
 55→  }
 56→}
