104→// ─── PlanCard ─────────────────────────────────────────────────────────────────
105→
106→const PLAN_DEBOUNCE_MS = 3_500
107→
108→export class PlanCard {
109→  private message?: Message
110→  private flushPromise: Promise<void> = Promise.resolve()
111→  private latestEntries?: PlanEntry[]
112→  private lastSentText?: string
113→  private flushTimer?: ReturnType<typeof setTimeout>
114→
115→  constructor(
116→    private thread: TextChannel | ThreadChannel,
117→    private sendQueue: DiscordSendQueue,
118→  ) {}
119→
120→  update(entries: PlanEntry[]): void {
121→    this.latestEntries = entries
122→    if (this.flushTimer) clearTimeout(this.flushTimer)
123→    this.flushTimer = setTimeout(() => {
124→      this.flushTimer = undefined
125→      this.flushPromise = this.flushPromise
126→        .then(() => this._flush())
127→        .catch(() => {})
128→    }, PLAN_DEBOUNCE_MS)
129→  }
130→
131→  async finalize(): Promise<void> {
132→    if (!this.latestEntries) return
133→    if (this.flushTimer) {
134→      clearTimeout(this.flushTimer)
135→      this.flushTimer = undefined
136→    }
137→    await this.flushPromise
138→    this.flushPromise = this.flushPromise
139→      .then(() => this._flush())
140→      .catch(() => {})
141→    await this.flushPromise
142→  }
143→
144→  destroy(): void {
145→    if (this.flushTimer) {
146→      clearTimeout(this.flushTimer)
147→      this.flushTimer = undefined
148→    }
149→  }
150→
151→  private async _flush(): Promise<void> {
152→    if (!this.latestEntries) return
153→    const text = formatPlan(this.latestEntries)
154→    if (this.message && text === this.lastSentText) return
155→    this.lastSentText = text
156→    const embed = new EmbedBuilder().setDescription(text)
157→    try {
158→      if (this.message) {
159→        await this.sendQueue.enqueue(
160→          () => this.message!.edit({ embeds: [embed] }),
161→          { type: 'other' },
162→        )
163→      } else {
164→        const result = await this.sendQueue.enqueue(
165→          () => this.thread.send({ embeds: [embed] }),
166→          { type: 'other' },
167→        )
168→        if (result) this.message = result
169→      }
170→    } catch (err) {
171→      log.warn({ err }, '[PlanCard] flush failed')
172→    }
173→  }
174→}
175→
176→// ─── ActivityTracker ──────────────────────────────────────────────────────────
177→
178→export class ActivityTracker {
179→  private isFirstEvent = true
180→  private hasPlanCard = false
181→  private thinking: ThinkingIndicator
182→  private planCard: PlanCard
183→  private usage: UsageMessage
184→
185→  constructor(
186→    private thread: TextChannel | ThreadChannel,
187→    private sendQueue: DiscordSendQueue,
188→  ) {
189→    this.thinking = new ThinkingIndicator(thread)
190→    this.planCard = new PlanCard(thread, sendQueue)
191→    this.usage = new UsageMessage(thread, sendQueue)
192→  }
193→
194→  async onNewPrompt(): Promise<void> {
195→    this.isFirstEvent = true
196→    this.hasPlanCard = false
197→    this.thinking.dismiss()
198→    this.thinking.reset()
199→  }
200→
201→  async onThought(): Promise<void> {
202→    await this._firstEventGuard()
203→    await this.thinking.show()
204→  }
205→
206→  async onTextStart(): Promise<void> {
207→    await this._firstEventGuard()
208→    this.thinking.dismiss()
209→  }
210→
211→  async onToolCall(): Promise<void> {
212→    await this._firstEventGuard()
213→    this.thinking.dismiss()
214→    this.thinking.reset()
215→  }
216→
217→  async onPlan(entries: PlanEntry[]): Promise<void> {
218→    await this._firstEventGuard()
219→    this.thinking.dismiss()
220→    this.hasPlanCard = true
221→    this.planCard.update(entries)
222→  }
223→
224→  async sendUsage(usage: { tokensUsed?: number; contextSize?: number }): Promise<void> {
225→    await this.usage.send(usage)
226→  }
227→
228→  async cleanup(): Promise<void> {
229→    this.thinking.dismiss()
230→    this.planCard.destroy()
231→    if (this.hasPlanCard) {
232→      await this.planCard.finalize()
233→    }
234→  }
235→
236→  private async _firstEventGuard(): Promise<void> {
237→    if (!this.isFirstEvent) return
238→    this.isFirstEvent = false
239→    await this.usage.delete()
240→  }
241→}
