107→  async send(usage: { tokensUsed?: number; contextSize?: number }): Promise<void> {
108→    const text = formatUsage(usage)
109→    try {
110→      if (this.msgId) {
111→        await this.sendQueue.enqueue(() =>
112→          this.api.editMessageText(this.chatId, this.msgId!, text, {
113→            parse_mode: 'HTML',
