148→
149→function formatPlanCard(entries: PlanEntry[]): string {
150→  const statusIcon: Record<string, string> = {
151→    completed: '✅',
152→    in_progress: '🔄',
153→    pending: '⬜',
154→    failed: '❌',
155→  }
156→  const total = entries.length
157→  const done = entries.filter(e => e.status === 'completed').length
158→  const ratio = total > 0 ? done / total : 0
159→  const filled = Math.round(ratio * 10)
160→  const bar = '▓'.repeat(filled) + '░'.repeat(10 - filled)
161→  const pct = Math.round(ratio * 100)
162→  const header = `📋 <b>Plan</b>\n${bar} ${pct}% · ${done}/${total}`
163→  const lines = entries.map((e, i) => {
164→    const icon = statusIcon[e.status] ?? '⬜'
165→    return `${icon} ${i + 1}. ${e.content}`
166→  })
167→  return [header, ...lines].join('\n')
168→}
169→
170→export class PlanCard {
171→  private msgId?: number
172→  private flushPromise: Promise<void> = Promise.resolve()
173→  private latestEntries?: PlanEntry[]
174→  private lastSentText?: string
175→  private flushTimer?: ReturnType<typeof setTimeout>
176→
177→  constructor(
178→    private api: Bot['api'],
179→    private chatId: number,
180→    private threadId: number,
181→    private sendQueue: TelegramSendQueue,
182→  ) {}
183→
184→  update(entries: PlanEntry[]): void {
185→    this.latestEntries = entries
186→    if (this.flushTimer) clearTimeout(this.flushTimer)
187→    this.flushTimer = setTimeout(() => {
188→      this.flushTimer = undefined
189→      this.flushPromise = this.flushPromise
190→        .then(() => this._flush())
191→        .catch(() => {})
192→    }, 3500)
193→  }
194→
195→  async finalize(): Promise<void> {
196→    if (!this.latestEntries) return
197→    if (this.flushTimer) {
198→      clearTimeout(this.flushTimer)
199→      this.flushTimer = undefined
200→    }
201→    await this.flushPromise
202→    this.flushPromise = this.flushPromise
203→      .then(() => this._flush())
204→      .catch(() => {})
205→    await this.flushPromise
206→  }
207→
208→  destroy(): void {
209→    if (this.flushTimer) {
210→      clearTimeout(this.flushTimer)
211→      this.flushTimer = undefined
212→    }
213→  }
214→
215→  private async _flush(): Promise<void> {
216→    if (!this.latestEntries) return
217→    const text = formatPlanCard(this.latestEntries)
218→    if (this.msgId && text === this.lastSentText) return
219→    this.lastSentText = text
220→    try {
221→      if (this.msgId) {
222→        await this.sendQueue.enqueue(() =>
223→          this.api.editMessageText(this.chatId, this.msgId!, text, {
224→            parse_mode: 'HTML',
225→          }),
226→        )
227→      } else {
228→        const result = await this.sendQueue.enqueue(() =>
229→          this.api.sendMessage(this.chatId, text, {
230→            message_thread_id: this.threadId,
231→            parse_mode: 'HTML',
232→            disable_notification: true,
233→          }),
234→        )
235→        if (result) this.msgId = result.message_id
236→      }
237→    } catch (err) {
238→      log.warn({ err }, 'PlanCard flush failed')
239→    }
240→  }
241→}
