245→export class ActivityTracker {
246→  private isFirstEvent = true
247→  private hasPlanCard = false
248→  private thinking: ThinkingIndicator
249→  private planCard: PlanCard
250→  private usage: UsageMessage
251→
252→  constructor(
253→    private api: Bot['api'],
