255→    private threadId: number,
256→    private sendQueue: TelegramSendQueue,
257→  ) {
258→    this.thinking = new ThinkingIndicator(api, chatId, threadId, sendQueue)
259→    this.planCard = new PlanCard(api, chatId, threadId, sendQueue)
260→    this.usage = new UsageMessage(api, chatId, threadId, sendQueue)
261→  }
262→
263→  async onNewPrompt(): Promise<void> {
264→    this.isFirstEvent = true
265→    this.hasPlanCard = false
266→    this.thinking.dismiss()
267→    this.thinking.reset()
268→  }
269→
270→  async onThought(): Promise<void> {
271→    await this._firstEventGuard()
272→    await this.thinking.show()
273→  }
274→
275→  async onPlan(entries: PlanEntry[]): Promise<void> {
276→    await this._firstEventGuard()
277→    this.thinking.dismiss()
278→    this.hasPlanCard = true
279→    this.planCard.update(entries)
280→  }
281→
282→  async onToolCall(): Promise<void> {
283→    await this._firstEventGuard()
284→    this.thinking.dismiss()
285→    this.thinking.reset()
286→  }
287→
288→  async onTextStart(): Promise<void> {
289→    await this._firstEventGuard()
290→    this.thinking.dismiss()
291→  }
292→
293→  async sendUsage(data: { tokensUsed?: number; contextSize?: number }): Promise<void> {
294→    await this.usage.send(data)
295→  }
296→
297→  getUsageMsgId(): number | undefined {
298→    return this.usage.getMsgId()
299→  }
300→
301→  async onComplete(): Promise<void> {
302→    if (this.hasPlanCard) {
303→      await this.planCard.finalize()
304→    } else {
305→      try {
306→        await this.sendQueue.enqueue(() =>
307→          this.api.sendMessage(this.chatId, '✅ <b>Done</b>', {
308→            message_thread_id: this.threadId,
309→            parse_mode: 'HTML',
310→            disable_notification: true,
311→          }),
312→        )
313→      } catch (err) {
314→        log.warn({ err }, 'ActivityTracker.onComplete() Done send failed')
315→      }
316→    }
317→  }
318→
319→  destroy(): void {
320→    this.thinking.dismiss()
321→    this.planCard.destroy()
322→  }
323→
324→  private async _firstEventGuard(): Promise<void> {
325→    if (!this.isFirstEvent) return
326→    this.isFirstEvent = false
327→    await this.usage.delete()
328→  }
329→}
