 69→/**
 70→ * Wraps native fetch to work around grammY's polyfilled AbortController.
 71→ * grammY uses abort-controller polyfill whose AbortSignal fails instanceof
 72→ * checks in Node 24+ native fetch. This wrapper re-creates a native
 73→ * AbortSignal from the polyfilled one before passing it to fetch.
 74→ */
 75→function patchedFetch(
 76→  input: RequestInfo | URL,
 77→  init?: RequestInit,
 78→): Promise<Response> {
 79→  if (init?.signal && !(init.signal instanceof AbortSignal)) {
 80→    const nativeController = new AbortController();
 81→    const polyfillSignal = init.signal as unknown as {
 82→      aborted: boolean;
 83→      addEventListener: (event: string, fn: () => void) => void;
 84→    };
 85→    if (polyfillSignal.aborted) {
 86→      nativeController.abort();
 87→    } else {
 88→      polyfillSignal.addEventListener("abort", () => nativeController.abort());
 89→    }
 90→    init = { ...init, signal: nativeController.signal };
 91→  }
 92→  return fetch(input, init);
 93→}
