141→  async start(): Promise<void> {
142→    this.bot = new Bot(this.telegramConfig.botToken, {
143→      client: {
144→        baseFetchConfig: { duplex: "half" } as RequestInit,
145→        fetch: patchedFetch,
146→      },
147→    });
148→    this.fileService = this.core.fileService;
149→
150→    // Initialize extracted managers
151→    this.toolTracker = new ToolCallTracker(
152→      this.bot,
153→      this.telegramConfig.chatId,
154→      this.sendQueue,
155→    );
156→    this.draftManager = new DraftManager(
157→      this.bot,
158→      this.telegramConfig.chatId,
159→      this.sendQueue,
160→    );
161→    this.skillManager = new SkillCommandManager(
162→      this.bot,
