167→
168→    // Global error handler — prevent unhandled errors from crashing the bot
169→    this.bot.catch((err) => {
170→      const rootCause = err.error instanceof Error ? err.error : err;
171→      log.error({ err: rootCause }, "Telegram bot error");
172→    });
173→
174→    // Auto-retry on 429 (Too Many Requests)
175→    this.bot.api.config.use(async (prev, method, payload, signal) => {
176→      const maxRetries = 3;
177→      for (let attempt = 0; attempt <= maxRetries; attempt++) {
178→        const result = await prev(method, payload, signal);
179→        if (
180→          result.ok ||
181→          (result as { error_code?: number }).error_code !== 429 ||
182→          attempt === maxRetries
183→        ) {
184→          return result;
185→        }
186→        const retryAfter =
187→          ((result as { parameters?: { retry_after?: number } }).parameters
188→            ?.retry_after ?? 5) + 1;
189→        const rateLimitedMethods = [
190→          "sendMessage",
191→          "editMessageText",
192→          "editMessageReplyMarkup",
193→        ];
194→        if (rateLimitedMethods.includes(method)) {
195→          this.sendQueue.onRateLimited();
196→        }
197→        log.warn(
198→          { method, retryAfter, attempt: attempt + 1 },
199→          "Rate limited by Telegram, retrying",
200→        );
201→        await new Promise((r) => setTimeout(r, retryAfter * 1000));
202→      }
203→      return prev(method, payload, signal);
204→    });
205→
206→    // Ensure allowed_updates includes callback_query on every poll
207→    this.bot.api.config.use((prev, method, payload, signal) => {
208→      if (method === "getUpdates") {
