 24→export function escapeHtml(text: string | undefined | null): string {
 25→  if (!text) return "";
 26→  return text
 27→    .replace(/&/g, "&amp;")
 28→    .replace(/</g, "&lt;")
 29→    .replace(/>/g, "&gt;");
 30→}
 31→
 32→export function markdownToTelegramHtml(md: string): string {
 33→  // Step 1: Extract code blocks and inline code into placeholders
 34→  const codeBlocks: string[] = [];
 35→  const inlineCodes: string[] = [];
 36→
 37→  // Extract fenced code blocks (```lang\n...\n```)
 38→  let text = md.replace(
 39→    /```(\w*)\n?([\s\S]*?)```/g,
 40→    (_match, lang: string, code: string) => {
 41→      const index = codeBlocks.length;
 42→      const escapedCode = escapeHtml(code);
 43→      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : "";
 44→      codeBlocks.push(`<pre><code${langAttr}>${escapedCode}</code></pre>`);
 45→      return `\x00CODE_BLOCK_${index}\x00`;
 46→    },
 47→  );
 48→
 49→  // Extract inline code (`...`)
 50→  text = text.replace(/`([^`]+)`/g, (_match, code: string) => {
 51→    const index = inlineCodes.length;
 52→    inlineCodes.push(`<code>${escapeHtml(code)}</code>`);
 53→    return `\x00INLINE_CODE_${index}\x00`;
 54→  });
 55→
 56→  // Step 2: Escape HTML in remaining text
 57→  text = escapeHtml(text);
 58→
 59→  // Step 3: Apply markdown transformations
 60→  // Bold: **text** → <b>text</b>
 61→  text = text.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");
 62→
 63→  // Italic: *text* → <i>text</i> (but not the ** used for bold)
 64→  text = text.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, "<i>$1</i>");
 65→
 66→  // Links: [text](url) → <a href="url">text</a>
 67→  // Note: after escapeHtml, parentheses are not affected, but we need to handle
 68→  // the escaped brackets properly. Since [ ] and ( ) are not escaped, this works directly.
 69→  text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
 70→
 71→  // Step 4: Restore fenced code blocks
 72→  text = text.replace(/\x00CODE_BLOCK_(\d+)\x00/g, (_match, idx: string) => {
 73→    return codeBlocks[parseInt(idx, 10)];
 74→  });
 75→
 76→  // Step 5: Restore inline code
 77→  text = text.replace(/\x00INLINE_CODE_(\d+)\x00/g, (_match, idx: string) => {
 78→    return inlineCodes[parseInt(idx, 10)];
 79→  });
 80→
 81→  return text;
 82→}
