 84→export function formatToolCall(
 85→  tool: ToolCallMeta,
 86→  verbosity: DisplayVerbosity = "medium",
 87→): string {
 88→  const si = STATUS_ICONS[tool.status || ""] || "🔧";
 89→  const name = tool.name || "Tool";
 90→  const label =
 91→    verbosity === "low"
 92→      ? formatToolTitle(name, tool.rawInput)
 93→      : formatToolSummary(name, tool.rawInput);
 94→  let text = `${si} <b>${escapeHtml(label)}</b>`;
 95→  text += formatViewerLinks(tool.viewerLinks, tool.viewerFilePath);
 96→  if (verbosity === "high" && !tool.viewerLinks) {
 97→    const details = stripCodeFences(extractContentText(tool.content));
 98→    if (details) {
 99→      text += `\n<pre>${escapeHtml(truncateContent(details, 3800))}</pre>`;
100→    }
101→  }
102→  return text;
103→}
