126→function formatViewerLinks(links?: ViewerLinks, filePath?: string): string {
127→  if (!links) return "";
128→  const fileName = filePath ? filePath.split("/").pop() || filePath : "";
129→  let text = "\n";
130→  if (links.file)
131→    text += `\n📄 <a href="${escapeHtml(links.file)}">View ${escapeHtml(fileName || "file")}</a>`;
132→  if (links.diff)
133→    text += `\n📝 <a href="${escapeHtml(links.diff)}">View diff${fileName ? ` — ${escapeHtml(fileName)}` : ""}</a>`;
134→  return text;
135→}
