152→export function formatUsage(usage: {
153→  tokensUsed?: number;
154→  contextSize?: number;
155→}): string {
156→  const { tokensUsed, contextSize } = usage;
157→  if (tokensUsed == null) return "📊 Usage data unavailable";
158→  if (contextSize == null) return `📊 ${formatTokens(tokensUsed)} tokens`;
159→
160→  const ratio = tokensUsed / contextSize;
161→  const pct = Math.round(ratio * 100);
162→  const bar = progressBar(ratio);
163→  const emoji = pct >= 85 ? "⚠️" : "📊";
164→  return `${emoji} ${formatTokens(tokensUsed)} / ${formatTokens(contextSize)} tokens\n${bar} ${pct}%`;
165→}
