  1→import type { Bot } from "grammy";
  2→import type { TelegramSendQueue } from "./send-queue.js";
  3→import { formatToolCall, formatToolUpdate } from "./formatting.js";
  4→import { createChildLogger } from "../../core/log.js";
  5→import type {
  6→  ToolCallMeta,
  7→  ViewerLinks,
  8→  DisplayVerbosity,
  9→} from "../shared/format-types.js";
 10→
 11→const log = createChildLogger({ module: "tool-call-tracker" });
 12→
 13→interface ToolCallState {
 14→  msgId: number;
 15→  name: string;
 16→  kind?: string;
 17→  rawInput?: unknown;
 18→  viewerLinks?: ViewerLinks;
 19→  viewerFilePath?: string;
 20→  ready: Promise<void>;
 21→}
 22→
 23→export class ToolCallTracker {
 24→  private sessions: Map<string, Map<string, ToolCallState>> = new Map();
 25→
 26→  constructor(
 27→    private bot: Bot,
 28→    private chatId: number,
 29→    private sendQueue: TelegramSendQueue,
 30→  ) {}
 31→
 32→  async trackNewCall(
 33→    sessionId: string,
 34→    threadId: number,
 35→    meta: ToolCallMeta,
 36→    verbosity: DisplayVerbosity = "medium",
 37→  ): Promise<void> {
 38→    if (!this.sessions.has(sessionId)) {
 39→      this.sessions.set(sessionId, new Map());
 40→    }
 41→
 42→    let resolveReady!: () => void;
 43→    const ready = new Promise<void>((r) => {
 44→      resolveReady = r;
 45→    });
 46→
 47→    this.sessions.get(sessionId)!.set(meta.id, {
 48→      msgId: 0,
 49→      name: meta.name,
 50→      kind: meta.kind,
 51→      rawInput: meta.rawInput,
 52→      viewerLinks: meta.viewerLinks,
 53→      viewerFilePath: meta.viewerFilePath,
 54→      ready,
 55→    });
 56→
 57→    const msg = await this.sendQueue.enqueue(() =>
 58→      this.bot.api.sendMessage(this.chatId, formatToolCall(meta, verbosity), {
 59→        message_thread_id: threadId,
 60→        parse_mode: "HTML",
 61→        disable_notification: true,
 62→      }),
 63→    );
 64→
 65→    const toolEntry = this.sessions.get(sessionId)!.get(meta.id)!;
 66→    toolEntry.msgId = msg!.message_id;
 67→    resolveReady();
 68→  }
 69→
 70→  async updateCall(
 71→    sessionId: string,
 72→    meta: ToolCallMeta & { status: string },
 73→    verbosity: DisplayVerbosity = "medium",
 74→  ): Promise<void> {
 75→    const toolState = this.sessions.get(sessionId)?.get(meta.id);
 76→    if (!toolState) return;
 77→
 78→    // Accumulate state from intermediate updates
 79→    if (meta.viewerLinks) {
 80→      toolState.viewerLinks = meta.viewerLinks;
 81→      log.debug(
 82→        { toolId: meta.id, viewerLinks: meta.viewerLinks },
 83→        "Accumulated viewerLinks",
 84→      );
 85→    }
 86→    if (meta.viewerFilePath) toolState.viewerFilePath = meta.viewerFilePath;
 87→    if (meta.name) toolState.name = meta.name;
 88→    if (meta.kind) toolState.kind = meta.kind;
 89→
 90→    // Only edit on terminal status — minimizes API calls to avoid rate limits
 91→    const isTerminal = meta.status === "completed" || meta.status === "failed";
 92→    if (!isTerminal) return;
 93→
 94→    await toolState.ready;
 95→
 96→    log.debug(
 97→      {
 98→        toolId: meta.id,
 99→        status: meta.status,
100→        hasViewerLinks: !!toolState.viewerLinks,
101→        viewerLinks: toolState.viewerLinks,
102→        name: toolState.name,
103→        msgId: toolState.msgId,
104→      },
105→      "Tool completed, preparing edit",
106→    );
107→
108→    const merged = {
109→      ...meta,
110→      name: toolState.name,
111→      kind: toolState.kind,
112→      rawInput: toolState.rawInput,
113→      viewerLinks: toolState.viewerLinks,
114→      viewerFilePath: toolState.viewerFilePath,
115→    };
116→    const formattedText = formatToolUpdate(merged, verbosity);
117→
118→    try {
119→      await this.sendQueue.enqueue(() =>
120→        this.bot.api.editMessageText(
121→          this.chatId,
122→          toolState.msgId,
123→          formattedText,
124→          { parse_mode: "HTML" },
125→        ),
126→      );
127→    } catch (err) {
128→      log.warn(
129→        {
130→          err,
131→          msgId: toolState.msgId,
132→          textLen: formattedText.length,
133→          hasViewerLinks: !!merged.viewerLinks,
134→        },
135→        "Tool update edit failed",
136→      );
137→    }
138→  }
139→
140→  cleanup(sessionId: string): void {
141→    this.sessions.delete(sessionId);
142→  }
143→}
144→

