 11→
 12→describe("splitMessage", () => {
 13→  it("returns array with original text when within maxLength", () => {
 14→    const text = "Hello world";
 15→    expect(splitMessage(text, 1800)).toEqual([text]);
 16→  });
 17→
 18→  it("splits long text at paragraph boundary", () => {
 19→    const para1 = "A".repeat(1000);
 20→    const para2 = "B".repeat(1000);
 21→    const text = para1 + "\n\n" + para2;
 22→    const chunks = splitMessage(text, 1800);
 23→    expect(chunks.length).toBeGreaterThan(1);
 24→    expect(chunks.join("\n\n").replace(/\n\n/g, "\n\n")).toContain("A");
 25→    expect(chunks.join("")).toContain("B");
 26→  });
 27→
 28→  it("splits long text at line boundary if no paragraph break", () => {
 29→    const lines = Array.from(
 30→      { length: 30 },
 31→      (_, i) => `Line ${i}: ${"x".repeat(60)}`,
 32→    ).join("\n");
 33→    const chunks = splitMessage(lines, 1800);
 34→    for (const chunk of chunks) {
 35→      expect(chunk.length).toBeLessThanOrEqual(2100); // some tolerance for fence logic
 36→    }
 37→  });
 38→
 39→  it("does not split inside a fenced code block", () => {
 40→    const before = "Some intro text\n\n";
 41→    const codeBlock =
 42→      "```javascript\n" + "const x = 1;\n".repeat(100) + "```\n";
 43→    const after = "\nAfter code block";
 44→    const text = before + codeBlock + after;
 45→    const chunks = splitMessage(text, 1800);
 46→    // No chunk should have an unclosed fenced code block
 47→    for (const chunk of chunks) {
 48→      const fences = chunk.match(/```/g) || [];
 49→      expect(fences.length % 2).toBe(0);
 50→    }
 51→  });
 52→
 53→  it("handles text exactly at maxLength", () => {
 54→    const text = "x".repeat(1800);
 55→    expect(splitMessage(text, 1800)).toEqual([text]);
 56→  });
 57→
 58→  it("handles text one char over maxLength", () => {
 59→    const text = "x".repeat(1801);
 60→    const chunks = splitMessage(text, 1800);
 61→    expect(chunks.length).toBeGreaterThan(1);
 62→  });
 63→});
